"use client";

import * as React from "react";
import { cn } from "@/utils/cn";

/* в”Җв”Җ Types в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
export interface BreadcrumbItem {
  /** н‘ңмӢңн•  л Ҳмқҙлё” */
  label: string;
  /** л§ҒнҒ¬ URL (м—Ҷмңјл©ҙ нҒҙлҰӯ л¶Ҳк°Җ) */
  href?: string;
  /** нҒҙлҰӯ н•ёл“Өлҹ¬ */
  onClick?: () => void;
}

export interface BreadcrumbsProps extends React.HTMLAttributes<HTMLElement> {
  /** лёҢл Ҳл“ңнҒ¬лҹј м•„мқҙн…ң лӘ©лЎқ */
  items: BreadcrumbItem[];
  /**
   * кө¬л¶„мһҗ нғҖмһ…
   * - slash: "/"
   * - chevron: ">"
   */
  separator?: "slash" | "chevron";
  /**
   * мөңлҢҖ н‘ңмӢң м•„мқҙн…ң мҲҳ
   * мҙҲкіј мӢң мӨ‘к°„мқ„ "..."мңјлЎң м¶•м•Ҫ
   * (кё°ліёк°’: м ңн•ң м—ҶмқҢ)
   */
  maxItems?: number;
  /** нҷҲ м•„мқҙмҪҳ н‘ңмӢң м—¬л¶Җ (кё°ліё: true) */
  showHomeIcon?: boolean;
}

/* в”Җв”Җ Separator в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
function Separator({ type }: { type: "slash" | "chevron" }) {
  return (
    <span className="text-ac-gray-50 select-none mx-1" aria-hidden="true">
      {type === "slash" ? "/" : ">"}
    </span>
  );
}

/* в”Җв”Җ Home Icon в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
function HomeIcon() {
  return (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      viewBox="0 0 16 16"
      fill="currentColor"
      className="w-3.5 h-3.5 shrink-0"
      aria-hidden="true"
    >
      <path d="M8.543 1.293a.75.75 0 0 0-1.086 0L1.5 7.25V13.5A1.5 1.5 0 0 0 3 15h3.25v-3.75a1.75 1.75 0 0 1 3.5 0V15H13a1.5 1.5 0 0 0 1.5-1.5V7.25L8.543 1.293Z" />
    </svg>
  );
}

/* в”Җв”Җ Breadcrumb Item в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
function BreadcrumbLink({
  item,
  isFirst,
  showHomeIcon,
  separator,
  isLast,
  isSingle,
}: {
  item: BreadcrumbItem;
  isFirst: boolean;
  showHomeIcon: boolean;
  separator: "slash" | "chevron";
  isLast: boolean;
  isSingle: boolean;
}) {
  // лӢЁлҸ… м•„мқҙн…ңмқҙл©ҙ isLastм—¬лҸ„ л§ҒнҒ¬ нҷңм„ұнҷ”
  const isClickable = (!isLast || isSingle) && (item.href || item.onClick);

  const content = (
    <span className="inline-flex items-center gap-1">
      {isFirst && showHomeIcon && <HomeIcon />}
      {item.label}
    </span>
  );

  return (
    <li className="inline-flex items-center">
      {isClickable ? (
        <a
          href={item.href}
          onClick={item.onClick}
          className={cn(
            "inline-flex items-center text-sm transition-colors duration-150",
            "text-ac-black hover:underline underline-offset-4",
          )}
          aria-label={isFirst && showHomeIcon ? "нҷҲмңјлЎң мқҙлҸҷ" : undefined}
        >
          {content}
        </a>
      ) : (
        <span
          className={cn(
            "inline-flex items-center text-sm",
            isLast && !isSingle
              ? "font-semibold text-foreground"   // нҳ„мһ¬ нҺҳмқҙм§Җ
              : "text-ac-gray-50 cursor-default",  // л§ҒнҒ¬ м—ҶлҠ” м•„мқҙн…ң
          )}
          aria-current={isLast && !isSingle ? "page" : undefined}
        >
          {content}
        </span>
      )}
      {!isLast && <Separator type={separator} />}
    </li>
  );
}

/* в”Җв”Җ Component в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
function Breadcrumbs({
  className,
  items,
  separator = "slash",
  maxItems,
  showHomeIcon = true,
  ...props
}: BreadcrumbsProps) {
  if (!items.length) return null;

  // maxItems мҙҲкіј мӢң мӨ‘к°„ м¶•м•Ҫ
  const visibleItems = React.useMemo(() => {
    if (!maxItems || items.length <= maxItems) return items;

    // мІ« лІҲм§ё + "..." + л§Ҳм§Җл§ү (maxItems - 2)к°ң
    const start = items.slice(0, 1);
    const end = items.slice(-(maxItems - 2));
    const ellipsis: BreadcrumbItem = { label: "..." };

    return [...start, ellipsis, ...end];
  }, [items, maxItems]);

  const isSingle = visibleItems.length === 1;

  return (
    <nav aria-label="breadcrumb" className={cn("w-full", className)} {...props}>
      <ol className="inline-flex flex-wrap items-center gap-y-1">
        {visibleItems.map((item, index) => (
          <BreadcrumbLink
            key={`${item.label}-${index}`}
            item={item}
            isFirst={index === 0}
            isLast={index === visibleItems.length - 1}
            isSingle={isSingle}
            showHomeIcon={showHomeIcon}
            separator={separator}
          />
        ))}
      </ol>
    </nav>
  );
}

export { Breadcrumbs };