import * as React from "react";
import { ChevronLeft, ChevronRight } from "lucide-react";
import { cn } from "@/utils/cn";

/* в”Җв”Җ Types в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
export type PaginationType = "simple" | "default";

/* в”Җв”Җ нҺҳмқҙм§Җ лІҲнҳё кі„мӮ° н—¬нҚј в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
function getPageNumbers(current: number, total: number, maxVisible = 10): (number | "...")[] {
  if (total <= maxVisible) return Array.from({ length: total }, (_, i) => i + 1);

  const pages: (number | "...")[] = [];
  const delta = 2; // нҳ„мһ¬ нҺҳмқҙм§Җ м–‘мӘҪ лӘҮ к°ңк№Ңм§Җ ліҙм—¬мӨ„м§Җ

  const left  = Math.max(2, current - delta);
  const right = Math.min(total - 1, current + delta);

  pages.push(1);
  if (left > 2) pages.push("...");
  for (let i = left; i <= right; i++) pages.push(i);
  if (right < total - 1) pages.push("...");
  pages.push(total);

  return pages;
}

/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
   Pagination (Root)
в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */
export interface PaginationProps extends Omit<React.HTMLAttributes<HTMLDivElement>, "onChange"> {
  /** м „мІҙ нҺҳмқҙм§Җ мҲҳ */
  total: number;
  /** нҳ„мһ¬ нҺҳмқҙм§Җ (controlled) */
  page?: number;
  defaultPage?: number;
  onPageChange?: (page: number) => void;
  /** simple: мқҙм „/нҳ„мһ¬/лӢӨмқҢл§Ң н‘ңмӢң */
  type?: PaginationType;
  /** л№„нҷңм„ұнҷ” */
  disabled?: boolean;
  /** нҷңм„ұ нҺҳмқҙм§Җ лІ„нҠј мғүмғҒ (кё°ліё ac-primary-50) */
  activeColor?: string;
  /** нҺҳмқҙм§ҖлӢ№ н•ӯлӘ© мҲҳ м„ нғқ н‘ңмӢң */
  showPageSize?: boolean;
  pageSizeOptions?: number[];
  pageSize?: number;
  defaultPageSize?: number;
  onPageSizeChange?: (size: number) => void;
  /** Go to нҺҳмқҙм§Җ м җн”„ мһ…л Ҙ н‘ңмӢң */
  showJumper?: boolean;
}

const Pagination = React.forwardRef<HTMLDivElement, PaginationProps>(
  (
    {
      className,
      total,
      page: controlledPage,
      defaultPage = 1,
      onPageChange,
      type = "default",
      disabled = false,
      activeColor,
      showPageSize = false,
      pageSizeOptions = [10, 20, 40, 100],
      pageSize: controlledPageSize,
      defaultPageSize = 10,
      onPageSizeChange,
      showJumper = false,
      ...props
    },
    ref
  ) => {
    const [internalPage, setInternalPage] = React.useState(defaultPage);
    const [internalPageSize, setInternalPageSize] = React.useState(defaultPageSize);
    const [jumperValue, setJumperValue] = React.useState("");

    const controlled     = controlledPage !== undefined;
    const page           = controlled ? controlledPage! : internalPage;
    const pageSizeControlled = controlledPageSize !== undefined;
    const pageSize       = pageSizeControlled ? controlledPageSize! : internalPageSize;

    const goTo = (p: number) => {
      if (disabled) return;
      const next = Math.max(1, Math.min(p, total));
      if (!controlled) setInternalPage(next);
      onPageChange?.(next);
    };

    const handlePageSizeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
      const size = Number(e.target.value);
      if (!pageSizeControlled) setInternalPageSize(size);
      onPageSizeChange?.(size);
      goTo(1);
    };

    const handleJumper = (e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === "Enter") {
        const target = Number(jumperValue);
        if (!isNaN(target) && target > 0) goTo(target);
        setJumperValue("");
      }
    };

    /* лІ„нҠј кіөнҶө мҠӨнғҖмқј */
    const btnBase = cn(
      "inline-flex items-center justify-center h-8 min-w-8 px-1 rounded-md text-sm",
      "transition-colors duration-fast select-none",
      "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
      disabled && "opacity-40 pointer-events-none"
    );
    const navBtn = cn(btnBase, "gap-1 px-2 text-foreground border border-border hover:bg-ac-gray-20 disabled:opacity-40");
    const pageBtn = (active: boolean) =>
      cn(btnBase, active
        ? "font-semibold text-ac-white"
        : "text-foreground hover:bg-ac-gray-20 hover:text-ac-primary-50"
      );

    /* в”Җв”Җ Simple нғҖмһ… в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
    if (type === "simple") {
      return (
        <div ref={ref} role="navigation" aria-label="нҺҳмқҙм§Җл„Өмқҙм…ҳ" className={cn("flex items-center gap-1", className)} {...props}>
          <button onClick={() => goTo(page - 1)} disabled={disabled || page <= 1} className={navBtn} aria-label="мқҙм „ нҺҳмқҙм§Җ">
            <ChevronLeft className="w-4 h-4" />
          </button>
          <span className="inline-flex items-center gap-1 px-2 text-sm text-foreground tabular-nums">
            <span className="font-semibold">{page}</span>
            <span className="text-muted-foreground">/ {total}</span>
          </span>
          <button onClick={() => goTo(page + 1)} disabled={disabled || page >= total} className={navBtn} aria-label="лӢӨмқҢ нҺҳмқҙм§Җ">
            <ChevronRight className="w-4 h-4" />
          </button>
        </div>
      );
    }

    /* в”Җв”Җ Default нғҖмһ… в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
    const pages = getPageNumbers(page, total);

    return (
      <div ref={ref} role="navigation" aria-label="нҺҳмқҙм§Җл„Өмқҙм…ҳ"
        className={cn("flex items-center gap-1 flex-wrap", className)} {...props}>

        {/* мқҙм „ */}
        <button onClick={() => goTo(page - 1)} disabled={disabled || page <= 1}
          className={navBtn} aria-label="мқҙм „ нҺҳмқҙм§Җ">
          <ChevronLeft className="w-4 h-4" />
          <span>мқҙм „</span>
        </button>

        {/* нҺҳмқҙм§Җ лІҲнҳё */}
        {pages.map((p, i) =>
          p === "..." ? (
            <span key={`ellipsis-${i}`} className="w-8 text-center text-sm text-muted-foreground select-none">
              вҖҰ
            </span>
          ) : (
            <button
              key={p}
              onClick={() => goTo(p as number)}
              disabled={disabled}
              aria-current={p === page ? "page" : undefined}
              className={pageBtn(p === page)}
              style={p === page ? { backgroundColor: activeColor ?? "#FF6300" /* ac-primary-50 */ } : undefined}
            >
              {p}
            </button>
          )
        )}

        {/* лӢӨмқҢ */}
        <button onClick={() => goTo(page + 1)} disabled={disabled || page >= total}
          className={navBtn} aria-label="лӢӨмқҢ нҺҳмқҙм§Җ">
          <span>лӢӨмқҢ</span>
          <ChevronRight className="w-4 h-4" />
        </button>

        {/* PageSize м„ нғқ */}
        {showPageSize && (
          <select
            value={pageSize}
            onChange={handlePageSizeChange}
            disabled={disabled}
            className={cn(
              "h-8 px-2 rounded-md border border-border text-sm bg-background text-foreground",
              "focus:outline-none focus:ring-2 focus:ring-ring",
              disabled && "opacity-40 pointer-events-none"
            )}
            aria-label="нҺҳмқҙм§ҖлӢ№ н•ӯлӘ© мҲҳ"
          >
            {pageSizeOptions.map(s => (
              <option key={s} value={s}>{s} / page</option>
            ))}
          </select>
        )}

        {/* Jumper */}
        {showJumper && (
          <div className="flex items-center gap-1.5 ml-1">
            <span className="text-sm text-foreground">Go to</span>
            <input
              type="number"
              min={1}
              max={total}
              value={jumperValue}
              onChange={(e) => setJumperValue(e.target.value)}
              onKeyDown={handleJumper}
              disabled={disabled}
              className={cn(
                "w-12 h-8 px-2 rounded-md border border-border text-sm bg-background text-foreground text-center tabular-nums",
                "focus:outline-none focus:ring-2 focus:ring-ring",
                disabled && "opacity-40 pointer-events-none"
              )}
              aria-label="мқҙлҸҷн•  нҺҳмқҙм§Җ лІҲнҳё"
            />
          </div>
        )}
      </div>
    );
  }
);
Pagination.displayName = "Pagination";

export { Pagination };